const input = $input.first().json || {};

function clean(value) {
  return String(value ?? '').trim();
}

function normalizePhone(value) {
  const raw = clean(value);
  if (!raw) return '';
  const withoutSpaces = raw.replace(/[\s()-]/g, '');
  if (withoutSpaces.startsWith('+')) return withoutSpaces.slice(1);
  return withoutSpaces;
}

function makeWaLink(to, message) {
  if (!to || !message) return '';
  return `https://wa.me/${to}?text=${encodeURIComponent(message)}`;
}

const action = clean(input.action || 'send_whatsapp_message');
const sessionId = clean(input.sessionId || input.session_id || '');
const userId = clean(input.userId || input.user_id || 'aliyan');
const contactName = clean(input.contactName || input.contact_name || input.name || '');
const to = normalizePhone(input.to || input.phone || input.whatsapp || input.whatsappNumber || input.whatsapp_number || '');
const message = clean(input.message || input.text || input.body || input.chatInput || input.query || '');

// Provider-ready values. In the next phase, pass these inputs from Main Brain or replace them with n8n credentials/env values.
const provider = clean(input.provider || 'meta_cloud');
const apiVersion = clean(input.whatsappApiVersion || input.apiVersion || 'v21.0');
const phoneNumberId = clean(input.whatsappPhoneNumberId || input.phoneNumberId || '');
const apiToken = clean(input.whatsappApiToken || input.apiToken || '');
const apiUrl = clean(input.whatsappApiUrl || (phoneNumberId ? `https://graph.facebook.com/${apiVersion}/${phoneNumberId}/messages` : ''));

const base = {
  success: false,
  agent: 'whatsapp',
  action,
  sessionId,
  userId,
  contactName,
  to,
  provider
};

if (!['send_whatsapp_message', 'draft_whatsapp_message', 'create_whatsapp_send_link'].includes(action)) {
  return [{
    json: {
      ...base,
      status: 'unsupported_action',
      reply: `WhatsApp Agent does not support action: ${action}`
    }
  }];
}

if (!message) {
  return [{
    json: {
      ...base,
      status: 'missing_message',
      reply: 'Please provide the WhatsApp message text.'
    }
  }];
}

if (!to) {
  return [{
    json: {
      ...base,
      status: 'missing_recipient',
      reply: contactName
        ? `I need ${contactName}'s WhatsApp number before I can send this.`
        : 'I need the recipient WhatsApp number before I can send this.'
    }
  }];
}

const whatsappUrl = makeWaLink(to, message);

if (action === 'draft_whatsapp_message' || action === 'create_whatsapp_send_link') {
  return [{
    json: {
      ...base,
      success: true,
      status: 'ready_to_send',
      message,
      whatsapp_url: whatsappUrl,
      reply: contactName
        ? `WhatsApp message prepared for ${contactName}.`
        : 'WhatsApp message prepared.'
    }
  }];
}

if (!apiUrl || !apiToken) {
  return [{
    json: {
      ...base,
      status: 'provider_not_configured',
      message,
      whatsapp_url: whatsappUrl,
      reply: 'WhatsApp auto-send is ready, but the WhatsApp API is not connected yet. Add API URL/token in the next phase.'
    }
  }];
}

const requestBody = {
  messaging_product: 'whatsapp',
  to,
  type: 'text',
  text: {
    preview_url: false,
    body: message
  }
};

try {
  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiToken}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(requestBody)
  });

  const rawResponse = await response.text();
  let parsedResponse;
  try {
    parsedResponse = JSON.parse(rawResponse);
  } catch {
    parsedResponse = { raw: rawResponse };
  }

  if (!response.ok) {
    return [{
      json: {
        ...base,
        status: 'send_failed',
        message,
        requestBody,
        providerResponse: parsedResponse,
        reply: `WhatsApp send failed: ${parsedResponse?.error?.message || response.statusText || 'Unknown provider error'}`
      }
    }];
  }

  return [{
    json: {
      ...base,
      success: true,
      status: 'sent',
      message,
      providerResponse: parsedResponse,
      reply: contactName
        ? `WhatsApp message sent to ${contactName}.`
        : 'WhatsApp message sent.'
    }
  }];
} catch (error) {
  return [{
    json: {
      ...base,
      status: 'send_error',
      message,
      reply: `WhatsApp send error: ${error.message}`
    }
  }];
}
